doc = Rhino.RhinoDoc.ActiveDoc
aware_layer = doc.Layers.FindName("AWARE")
if aware_layer is None:
    return {"ok": False, "error": "layer 'AWARE' does not exist; create it first (prompt 10)"}
aware_index = aware_layer.Index
moved = 0
for obj in doc.Objects.GetSelectedObjects(False, False):
    attrs = obj.Attributes.Duplicate()
    attrs.LayerIndex = aware_index
    if doc.Objects.ModifyAttributes(obj, attrs, False):
        moved += 1
doc.Views.Redraw()
return {"ok": True, "moved": moved, "target_layer": "AWARE"}
